from pydantic_settings import BaseSettings, SettingsConfigDictfrom pydantic import EmailStr, Field, AnyHttpUrl, validatorfrom typing import List, Optionalfrom pathlib import Pathfrom dotenv import load_dotenvfrom pathlib import Pathenv_path = Path(__file__).resolve().parent.parent / ".env"load_dotenv(dotenv_path=env_path)class Settings(BaseSettings):    # —— App & DB ——    APP_HOST: str = "0.0.0.0"    APP_PORT: int = 8047    DB_HOST: str    DB_USER: str    DB_PASSWORD: str    DB_NAME: str    SQLALCHEMY_DATABASE_URL: str    FRONTEND_URL: AnyHttpUrl    SENDGRID_SMTP_SERVER: str = "smtp.sendgrid.net"    SENDGRID_SMTP_PORT: int = 587    SENDGRID_USERNAME: str = "apikey"    SENDGRID_PASSWORD: str    SMTP_FROM: str = "no-reply@anime-seek.com"    SECRET_KEY: str    # —— Stripe & JWT ——    STRIPE_SECRET_KEY: str    STRIPE_PUBLISHABLE_KEY: str    STRIPE_WEBHOOK_SECRET: str    STRIPE_PRICE_WATCHER: str    STRIPE_PRICE_OTAKU: str    STRIPE_PRICE_SENPAI: str    STRIPE_PRICE_KAMISAMA: str    ALGORITHM: str = "HS256"    ACCESS_EXPIRE_MINUTES: int = 60    REFRESH_EXPIRE_DAYS: int = 7    # —— Redis / rate-limiting ——    REDIS_HOST: str = "localhost"    REDIS_PORT: int = 6379    RATE_LIMIT_COUNT: int = 5    RATE_LIMIT_WINDOW: int = 300    # —— Uploads & external services ——    MAX_UPLOAD_SIZE: int = 5 * 1024 * 1024    SOLR_URL: str = "http://localhost:8983/solr/cl_0/lireq"    ANILIST_API: str    # —— CORS & Static ——    ALLOWED_ORIGINS: List[str] = Field(        default_factory=lambda: ["https://anime-seek.com"]    )    STATIC_DIR: str = "static"    # —— OAuth/Social Login ——    OAUTH_GOOGLE_CLIENT_ID: Optional[str] = None    OAUTH_GOOGLE_CLIENT_SECRET: Optional[str] = None    # pydantic-settings v2 config (replaces old `class Config`)    model_config = SettingsConfigDict(        env_file=[            "/app/.env",  # inside container            str(Path(__file__).parent.parent / ".env"),  # repo root        ],        env_file_encoding="utf-8",        extra="ignore",    )    @validator("ALLOWED_ORIGINS", pre=True)    def _split_origins(cls, v):        if isinstance(v, str):            return [origin.strip() for origin in v.split(",") if origin.strip()]        return vsettings = Settings()